+  private getCursorOrder(orderBy: CrudOptions['orderBy']) {
+    if (!orderBy) {
+      return undefined;
+    }
+    const fields: { field: string; dir: 'asc' | 'desc' }[] = [];
+    for (const item of Array.isArray(orderBy) ? orderBy : [orderBy]) {
+      if (!item || typeof item !== 'object' || Array.isArray(item)) {
+        return undefined;
+      }
+      for (const [field, value] of Object.entries(item)) {
+        const dir = this.normalizeCursorDirection(value);
+        if (!dir) {
+          return undefined;
+        }
+        fields.push({ field, dir });
+      }
+    }
+    if (!fields.length) {
+      return undefined;
+    }
+    const idField = this.crudConfig.id_field;
+    if (!fields.some(({ field }) => field === idField)) {
+      fields.push({ field: idField, dir: 'asc' });
+    }
+    return fields;
+  }
+
+  private normalizeCursorDirection(value: unknown): 'asc' | 'desc' | undefined {
+    if (value === 1) return 'asc';
+    if (value === -1) return 'desc';
+    const normalized = String(value).toLowerCase();
+    if (normalized === 'asc') return 'asc';
+    if (normalized === 'desc') return 'desc';
+    return undefined;
+  }
+
+  private decodeCursor(
+    cursor: string,
