+    let payload: Record<string, any>;
+    try {
+      const json = Buffer.from(cursor, 'base64').toString('utf8');
+      payload = JSON.parse(json);
+    } catch {
+      throw new BadRequestException('cursor must be Base64-encoded JSON');
+    }
+    if (!payload || typeof payload !== 'object' || Array.isArray(payload)) {
+      throw new BadRequestException('cursor must be Base64-encoded JSON');
+    }
+    const sort = order.map(({ field, dir }) => `${field}:${dir}`).join(',');
+    if (payload.__sort !== sort) {
+      throw new BadRequestException('cursor sort does not match orderBy');
+    }
+    const idField = this.crudConfig.id_field;
+    if (!Object.prototype.hasOwnProperty.call(payload, idField)) {
+      throw new BadRequestException('cursor is missing the entity ID');
+    }
+    for (const { field } of order) {
+      if (!Object.prototype.hasOwnProperty.call(payload, field)) {
+        throw new BadRequestException(`cursor is missing sort field ${field}`);
